import { 
    DELETE_PRODUCTS, 
    UPDATE_PRODUCTS, 
    CREATE_PRODUCTS, 
    GET_PRODUCT_LIKE, 
    GET_PRODUCT_DETALIS, 
    GET_ALL_PRODUCTS, 
    GET_ERROR 
} from '../type'

const inital = {
    products: [],
    allProducts: [],
    oneProduct: {},
    productLike: [],
    deleteProducts: [],
    updateProducts: [],
    loading: true,
}

const productsReducer = (state = inital, action) => {
    switch (action.type) {
        case CREATE_PRODUCTS:
            return {
                ...state,
                products: action.payload || [], // ✅ تأكد من وجود payload
                loading: false,
            }
        case GET_ALL_PRODUCTS:
            return {
                ...state,
                allProducts: action.payload || [], // ✅ تأكد من وجود payload
                loading: false,
            }
        case GET_PRODUCT_DETALIS:
            return {
                ...state,
                oneProduct: action.payload || {}, // ✅ تأكد من وجود payload
                loading: false,
            }
        case GET_PRODUCT_LIKE:
            return {
                ...state,
                productLike: action.payload || [], // ✅ تأكد من وجود payload
                loading: false,
            }
        case DELETE_PRODUCTS:
            return {
                ...state,
                deleteProducts: action.payload || [], // ✅ تأكد من وجود payload
                loading: false,
            }
        case UPDATE_PRODUCTS:
            return {
                ...state,
                updateProducts: action.payload || [], // ✅ تأكد من وجود payload
                loading: false,
            }
        case GET_ERROR:
            return {
                ...state,
                loading: false,
                products: action.payload || [],
            }
        default:
            return state;
    }
}

export default productsReducer